<?php
/**
 * Template Name: Testimonials
 */
get_header(); the_post(); get_template_part( 'template-parts/page-hero' ); $testimonials = new WP_Query( array( 'post_type' => 'wma_testimonial', 'post_status' => 'publish', 'posts_per_page' => 12, 'orderby' => 'menu_order date', 'order' => 'DESC' ) ); ?>
<section class="wma-section"><div class="wma-container"><div class="wma-prose wma-prose--intro"><?php the_content(); ?></div><?php if ( $testimonials->have_posts() ) : ?><div class="wma-testimonial-grid wma-testimonial-grid--archive"><?php while ( $testimonials->have_posts() ) : $testimonials->the_post(); ?><blockquote><div class="wma-stars"><?php echo esc_html( str_repeat( '★', absint( get_post_meta( get_the_ID(), '_wma_rating', true ) ) ) ); ?></div><?php the_content(); ?><footer><strong><?php the_title(); ?></strong><span><?php echo esc_html( (string) get_post_meta( get_the_ID(), '_wma_location', true ) ); ?></span></footer></blockquote><?php endwhile; ?></div><?php else : ?><div class="wma-empty-card"><h2><?php esc_html_e( 'Traveller stories are being prepared.', 'wild-morocco-adventures' ); ?></h2><p><?php esc_html_e( 'Only verified, permission-cleared reviews are published here. In the meantime, explore the journey ideas or request a personal proposal.', 'wild-morocco-adventures' ); ?></p><a class="wma-button wma-button--primary" href="<?php echo esc_url( wma_quote_url() ); ?>"><?php esc_html_e( 'Request a quote', 'wild-morocco-adventures' ); ?></a></div><?php endif; wp_reset_postdata(); ?></div></section><?php get_footer(); ?>
